import React from 'react';
import { useNavigate } from 'react-router-dom';

export default function Cart() {
  const navigate = useNavigate();
  const cart = JSON.parse(localStorage.getItem('cart') || '{}');

  const TOPPING_PRICE = 8;

  // ── Page Shell ──────────────────────────────────────────────────────────────
  const Header = () => (
    <div className="bg-white border-b border-gray-100 px-5 py-4 flex items-center relative">
      <button
        onClick={() => navigate('/')}
        className="absolute right-4 text-dark"
      >
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none"
          stroke="#1A1A1A" strokeWidth="1.8" strokeLinecap="round">
          <path d="M19 12H5M12 19l-7-7 7-7"/>
        </svg>
      </button>
      <div className="flex-1 text-center">
        <span className="font-black text-xl tracking-widest text-dark">PIZZA STORY</span>
      </div>
    </div>
  );

  if (!cart.toppings) {
    return (
      <div className="max-w-md mx-auto min-h-screen bg-white">
        <Header />
        <div className="flex flex-col items-center justify-center py-28 text-center px-8">
          <div
            className="w-24 h-24 rounded-full flex items-center justify-center mb-5"
            style={{ background: '#FFC10715' }}
          >
            <svg width="40" height="40" viewBox="0 0 24 24" fill="none"
              stroke="#1A1A1A" strokeWidth="1.5" strokeLinecap="round">
              <path d="M6 2L3 6v14a2 2 0 002 2h14a2 2 0 002-2V6l-3-4z"/>
              <line x1="3" y1="6" x2="21" y2="6"/>
              <path d="M16 10a4 4 0 01-8 0"/>
            </svg>
          </div>
          <p className="text-xl font-black text-dark mb-2">הסל ריק</p>
          <p className="text-gray-400 text-sm mb-8">הוסיפו פיצה כדי להמשיך</p>
          <button
            onClick={() => navigate('/')}
            className="font-black text-dark px-10 py-4 rounded-full transition active:scale-95 shadow-sm"
            style={{ background: '#FFC107' }}
          >
            לתפריט
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white">
      <Header />

      <div className="px-4 pt-5 pb-10 space-y-4">

        {/* ── Pizza Item Card ── */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden flex gap-4 p-4">
          <img
            src="https://images.unsplash.com/photo-1513104890138-7c749659a591?auto=format&fit=crop&w=120&q=80"
            alt="pizza"
            className="w-20 h-20 rounded-xl object-cover flex-shrink-0"
          />
          <div className="flex-1 min-w-0 py-1">
            <p className="font-black text-dark text-lg">פיצה קלאסית</p>
            <p className="text-gray-400 text-xs mt-0.5">בצק טרי · רוטב ביתי · מוצרלה</p>
            {cart.toppings.length > 0 && (
              <p className="text-gray-500 text-xs mt-1.5 leading-relaxed">
                + {cart.toppings.join(', ')}
              </p>
            )}
          </div>
        </div>

        {/* ── Price Breakdown ── */}
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm p-5 space-y-3">
          <p className="font-black text-dark text-sm mb-1">סיכום</p>

          <div className="flex justify-between text-sm text-gray-500">
            <span>פיצה בסיסית</span>
            <span className="font-semibold text-dark">30₪</span>
          </div>

          {cart.toppings.map(t => (
            <div key={t} className="flex justify-between text-sm text-gray-400">
              <span>+ {t}</span>
              <span>+{TOPPING_PRICE}₪</span>
            </div>
          ))}

          <div className="border-t border-gray-100 pt-3 flex justify-between items-center">
            <span className="font-black text-dark text-lg">סה"כ</span>
            <span className="font-black text-dark text-2xl">{cart.total}₪</span>
          </div>
        </div>

        {/* ── Edit ── */}
        <button
          onClick={() => navigate('/')}
          className="w-full py-3.5 rounded-full border-2 border-gray-200 font-bold text-dark text-sm hover:bg-gray-50 transition active:scale-95"
        >
          ✏️  ערוך הזמנה
        </button>

        {/* ── Checkout CTA ── */}
        <button
          onClick={() => navigate('/checkout')}
          className="w-full font-black text-dark text-xl py-4 rounded-full flex items-center justify-between px-6 transition active:scale-95 shadow-sm"
          style={{ background: '#FFC107' }}
        >
          <span>לתשלום</span>
          <span
            className="bg-dark text-white px-3 py-1 rounded-full font-bold text-base"
          >{cart.total}₪</span>
        </button>
      </div>
    </div>
  );
}
